__m256i *simdpack_shortlength(const uint32_t *in, int length, __m256i *out,
                              const uint32_t bit) {
  int k;
  int inwordpointer;
  __m256i P;
  uint32_t firstpass;
  if (bit == 0)
    return out; /* nothing to do */
  if (bit == 32) {
    memcpy(out, in, length * sizeof(uint32_t));
    return (__m256i *)((uint32_t *)out + length);
  }
  inwordpointer = 0;
  P = _mm256_setzero_si256();
  for (k = 0; k < length / 8; ++k) {
    __m256i value = _mm256_loadu_si256(((const __m256i *)in + k));
    P = _mm256_or_si256(P, _mm256_slli_epi32(value, inwordpointer));
    firstpass = sizeof(uint32_t) * 8 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else {
      _mm256_storeu_si256(out++, P);
      P = _mm256_srli_epi32(value, firstpass);
      inwordpointer = bit - firstpass;
    }
  }
  if (length % 8 != 0) {
    uint32_t buffer[8];
    __m256i value;
    for (k = 0; k < (length % 8); ++k) {
      buffer[k] = in[length / 8 * 8 + k];
    }
    for (k = (length % 8); k < 8; ++k) {
      buffer[k] = 0;
    }
    value = _mm256_loadu_si256((__m256i *)buffer);
    P = _mm256_or_si256(P, _mm256_slli_epi32(value, inwordpointer));
    firstpass = sizeof(uint32_t) * 8 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else {
      _mm256_storeu_si256(out++, P);
      P = _mm256_srli_epi32(value, firstpass);
      inwordpointer = bit - firstpass;
    }
  }
  if (inwordpointer != 0) {
    _mm256_storeu_si256(out++, P);
  }
  return out;
}

const __m256i *simdunpack_shortlength(const __m256i *in, int length,
                                      uint32_t *out, const uint32_t bit) {
  int k;
  __m256i maskbits;
  int inwordpointer;
  __m256i P;
  if (length == 0)
    return in;
  if (bit == 0) {
    for (k = 0; k < length; ++k) {
      out[k] = 0;
    }
    return in;
  }
  if (bit == 32) {
    memcpy(out, in, length * sizeof(uint32_t));
    return (const __m256i *)((uint32_t *)in + length);
  }
  maskbits = _mm256_set1_epi32((1U << bit) - 1);
  inwordpointer = 0;
  P = _mm256_loadu_si256((__m256i *)in);
  ++in;
  if (length % 8 == 0) {

    for (k = 0; k + 1 < length / 8; ++k) {
      __m256i answer = _mm256_srli_epi32(P, inwordpointer);
      const uint32_t firstpass = sizeof(uint32_t) * 8 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi32(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 8;
    }
    if (k < length / 8) {
      __m256i answer = _mm256_srli_epi32(P, inwordpointer);
      const uint32_t firstpass = sizeof(uint32_t) * 8 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else if (bit == firstpass) {
        inwordpointer = 0;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi32(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 8;
    }

  } else {
    for (k = 0; k < length / 8; ++k) {
      __m256i answer = _mm256_srli_epi32(P, inwordpointer);
      const uint32_t firstpass = sizeof(uint32_t) * 8 - inwordpointer;
      if (bit < firstpass) {
        inwordpointer += bit;
      } else {
        P = _mm256_loadu_si256((__m256i *)in);
        ++in;
        answer = _mm256_or_si256(_mm256_slli_epi32(P, firstpass), answer);
        inwordpointer = bit - firstpass;
      }
      answer = _mm256_and_si256(maskbits, answer);
      _mm256_storeu_si256((__m256i *)out, answer);
      out += 8;
    }
    uint32_t buffer[8];
    __m256i answer = _mm256_srli_epi32(P, inwordpointer);
    const uint32_t firstpass = sizeof(uint32_t) * 8 - inwordpointer;
    if (bit < firstpass) {
      inwordpointer += bit;
    } else if (bit == firstpass) {
      inwordpointer = 0;
    } else {
      P = _mm256_loadu_si256((__m256i *)in);
      ++in;
      answer = _mm256_or_si256(_mm256_slli_epi32(P, firstpass), answer);
      inwordpointer = bit - firstpass;
    }
    answer = _mm256_and_si256(maskbits, answer);
    _mm256_storeu_si256((__m256i *)buffer, answer);
    for (k = 0; k < (length % 8); ++k) {
      *out = buffer[k];
      ++out;
    }
  }
  return in;
}

void simdfastset(__m256i *in128, uint32_t b, uint32_t value, size_t index) {
  uint32_t *in = (uint32_t *)in128;
  const int lane = index % 8;             /* we have 8 interleaved lanes */
  const int bitsinlane = (index / 8) * b; /* how many bits in lane */
  const int firstwordinlane = bitsinlane / 32;
  const int secondwordinlane = (bitsinlane + b - 1) / 32;
  const uint32_t mask = (1U << b) - 1;
  if (b == 0)
    return;
  /* we zero */
  if (b == 32)
    in[8 * firstwordinlane + lane] = 0;
  else
    in[8 * firstwordinlane + lane] &= ~(mask << (bitsinlane % 32));

  /* we write */
  in[8 * firstwordinlane + lane] |= (value << (bitsinlane % 32));

  if (firstwordinlane == secondwordinlane) {
    /* easy common case*/
    return;
  } else {
    /* harder case where we need to combine two words */
    const int firstbits = 32 - (bitsinlane % 32);
    const int usablebits = b - firstbits;
    const uint32_t mask2 = (1U << usablebits) - 1;
    in[8 * firstwordinlane + 8 + lane] &= ~mask2;             /* we zero */
    in[8 * firstwordinlane + 8 + lane] |= value >> firstbits; /* we write */
    return;
  }
}

int simdpack_compressedbytes(int length, const uint32_t bit) {
  if (bit == 0)
    return 0; /* nothing to do */
  if (bit == 32) {
    return length * sizeof(uint32_t);
  }
  return (((length + 7) / 8) * bit + 31) / 32 * sizeof(__m256i);
}

__m256i *simdpack_length(const uint32_t *in, size_t length, __m256i *out,
                         const uint32_t bit) {
  size_t k;
  for (k = 0; k < length / SIMDBlockSize; ++k) {
    simdpack(in, out, bit);
    in += SIMDBlockSize;
    out += bit;
  }
  return simdpack_shortlength(in, length % SIMDBlockSize, out, bit);
}

const __m256i *simdunpack_length(const __m256i *in, size_t length,
                                 uint32_t *out, const uint32_t bit, uint64_t* outsum) {
  __m256i sum_lo = _mm256_setzero_si256();
  __m256i sum_hi = _mm256_setzero_si256();
  size_t k;
  for (k = 0; k < length / SIMDBlockSize; ++k) {
    simdunpack(in, out, bit, &sum_lo, &sum_hi);
    out += SIMDBlockSize;
    in += bit;
  }
  /* 256-bit horizontal sum */
  __m128i lo = _mm256_castsi256_si128(sum_lo);
  __m128i hi = _mm256_extracti128_si256(sum_lo, 1);
  __m128i s = _mm_add_epi32(lo, hi);
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(1,0,3,2)));
  s = _mm_add_epi32(s, _mm_shuffle_epi32(s, _MM_SHUFFLE(2,3,0,1)));

  uint64_t sum = (uint32_t)_mm_cvtsi128_si32(s);
  size_t remainder = length % SIMDBlockSize;
  if (remainder > 0) {
      in = simdunpack_shortlength(in, remainder, out, bit);
      size_t i;
      for (i = 0; i < remainder; ++i) {
          sum += out[i];
      }
  }
  *outsum = sum;
  return in;
}
